/* ══════════════════════════════════════════════════════════════════════════
   PBI Genie Visual — Databricks Genie-inspired design
   ══════════════════════════════════════════════════════════════════════════ */
/* ── Design tokens ─────────────────────────────────────────────────────── */
.rx-shell {
  --color-base: #f7f8fa;
  --color-surface: #ffffff;
  --color-surface-subtle: #f0f2f5;
  --color-surface-strong: #e4e8ed;
  --color-border: #e1e4e8;
  --color-border-subtle: #eef0f3;
  --color-text: #1b1f23;
  --color-text-secondary: #586069;
  --color-text-tertiary: #8b949e;
  --color-accent: #2563eb;
  --color-accent-subtle: rgba(37, 99, 235, 0.08);
  --color-accent-hover: #1d4ed8;
  --color-success: #16a34a;
  --color-warning: #d97706;
  --color-error: #dc2626;
  --color-user-bubble: #1a73e8;
  --color-code-bg: #f6f8fa;
  --color-code-border: #e1e4e8;
  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 16px;
  --radius-xl: 20px;
  --spacing-xs: 4px;
  --spacing-sm: 8px;
  --spacing-md: 12px;
  --spacing-lg: 16px;
  --spacing-xl: 24px;
  display: flex;
  flex-direction: column;
  width: 100%;
  height: 100%;
  min-height: 0;
  background: var(--color-base);
  color: var(--color-text);
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  font-size: 13px;
  line-height: 1.55;
  overflow: hidden;
}
/* ── Dark mode (Databricks-inspired dark) ────────────────────────────── */
.rx-shell--dark {
  --color-base: #0d1117;
  --color-surface: #161b22;
  --color-surface-subtle: #1c2129;
  --color-surface-strong: #262c36;
  --color-border: #2d333b;
  --color-border-subtle: #21262d;
  --color-text: #e6edf3;
  --color-text-secondary: #9ca3af;
  --color-text-tertiary: #6b7280;
  --color-accent: #58a6ff;
  --color-accent-subtle: rgba(88, 166, 255, 0.1);
  --color-accent-hover: #79b8ff;
  --color-success: #3fb950;
  --color-warning: #d29922;
  --color-error: #f85149;
  --color-user-bubble: #1f6feb;
  --color-code-bg: #0d1117;
  --color-code-border: #2d333b;
}
/* ── Header ──────────────────────────────────────────────────────────── */
.rx-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-lg);
  background: var(--color-surface);
  border-bottom: 1px solid var(--color-border);
  flex-shrink: 0;
  min-height: 42px;
}
.rx-title {
  font-size: 14px;
  font-weight: 700;
  letter-spacing: -0.01em;
}
.rx-header-actions {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}
/* ── Connection indicator ────────────────────────────────────────────── */
.rx-connection-indicator {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 3px 10px;
  border-radius: 999px;
  border: 1px solid var(--color-border);
  background: var(--color-surface-subtle);
  font-size: 11px;
  font-weight: 600;
  color: var(--color-text-tertiary);
}
.rx-connection-indicator--online {
  border-color: color-mix(in srgb, var(--color-success) 35%, var(--color-border));
  color: var(--color-success);
}
.rx-connection-indicator--offline {
  border-color: color-mix(in srgb, var(--color-error) 35%, var(--color-border));
  color: var(--color-error);
}
.rx-connection-indicator--checking {
  border-color: color-mix(in srgb, var(--color-warning) 35%, var(--color-border));
  color: var(--color-warning);
}
.rx-connection-dot {
  width: 6px;
  height: 6px;
  border-radius: 999px;
  background: currentColor;
  flex-shrink: 0;
}
/* ── Chat body ───────────────────────────────────────────────────────── */
.rx-chat-body {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}
/* ── Context strip ───────────────────────────────────────────────────── */
.rx-context-strip {
  padding: var(--spacing-xs) var(--spacing-lg);
  border-bottom: 1px solid var(--color-border);
  background: var(--color-surface);
  flex-shrink: 0;
}
.rx-chip-row {
  display: flex;
  gap: var(--spacing-xs);
  flex-wrap: wrap;
  overflow-y: auto;
  max-height: 52px;
}
.rx-chip {
  display: inline-flex;
  align-items: center;
  padding: 2px 10px;
  border-radius: 999px;
  border: 1px solid var(--color-border);
  background: var(--color-surface-subtle);
  color: var(--color-text);
  font-size: 11px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  transition: border-color 120ms, color 120ms;
}
.rx-chip:hover {
  border-color: var(--color-accent);
  color: var(--color-accent);
}
.rx-chip--active {
  border-color: var(--color-accent);
  background: var(--color-accent-subtle);
  color: var(--color-accent);
  font-weight: 600;
}
.rx-chip--clear {
  background: none;
  border-color: transparent;
  color: var(--color-text-tertiary);
  font-weight: 600;
}
.rx-chip--clear:hover {
  color: var(--color-error);
  border-color: transparent;
}
/* ── Chat area ───────────────────────────────────────────────────────── */
.rx-chat {
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  padding: var(--spacing-lg);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-md);
}
/* ── Empty state ─────────────────────────────────────────────────────── */
.rx-empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  flex: 1;
  padding: var(--spacing-xl);
  text-align: center;
}
.rx-empty-icon {
  color: var(--color-text-tertiary);
  margin-bottom: var(--spacing-md);
  opacity: 0.5;
}
.rx-empty-kicker {
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--color-accent);
  margin-bottom: var(--spacing-xs);
}
.rx-empty-state h3 {
  margin: 0 0 var(--spacing-sm);
  font-size: 16px;
  font-weight: 700;
}
.rx-empty-state p {
  margin: 0;
  max-width: 44ch;
  color: var(--color-text-secondary);
  font-size: 13px;
}
.rx-prompt-row {
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--spacing-sm);
  margin-top: var(--spacing-lg);
}
.rx-prompt {
  padding: 8px 16px;
  border-radius: var(--radius-lg);
  border: 1px solid var(--color-border);
  background: var(--color-surface);
  color: var(--color-text);
  font-size: 12px;
  font-weight: 500;
  cursor: pointer;
  text-align: left;
  transition: border-color 120ms, background 120ms;
  max-width: 280px;
}
.rx-prompt:hover {
  border-color: var(--color-accent);
  background: var(--color-accent-subtle);
}
/* ── Messages ────────────────────────────────────────────────────────── */
.rx-msg {
  display: flex;
  animation: rx-fade-in 200ms ease-out;
}
@keyframes rx-fade-in {
  from {
    opacity: 0;
    transform: translateY(6px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
/* ── User message ────────────────────────────────────────────────────── */
.rx-msg--user {
  justify-content: flex-end;
}
.rx-user-bubble {
  max-width: min(80%, 560px);
  padding: var(--spacing-sm) var(--spacing-lg);
  border-radius: var(--radius-lg);
  border-bottom-right-radius: var(--radius-sm);
  background: var(--color-user-bubble);
  color: #ffffff;
  font-size: 13px;
  line-height: 1.55;
  overflow-wrap: anywhere;
}
/* ── Assistant / Genie response ──────────────────────────────────────── */
.rx-msg--assistant {
  justify-content: flex-start;
}
.rx-genie-response {
  width: 100%;
  max-width: 720px;
  display: flex;
  flex-direction: column;
  gap: 0;
}
.rx-genie-response--loading {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: var(--spacing-sm);
  padding: var(--spacing-md) 0;
}
/* ── Analysis disclosure ─────────────────────────────────────────────── */
.rx-analysis {
  margin-bottom: var(--spacing-sm);
}
.rx-analysis-summary {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 4px 0;
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-secondary);
  cursor: pointer;
  user-select: none;
  list-style: none;
}
.rx-analysis-summary::-webkit-details-marker {
  display: none;
}
.rx-analysis-summary svg {
  transition: transform 150ms;
}
.rx-analysis[open] .rx-analysis-summary svg {
  transform: rotate(180deg);
}
.rx-analysis-tag {
  padding: 1px 6px;
  border-radius: var(--radius-sm);
  background: var(--color-surface-subtle);
  border: 1px solid var(--color-border);
  font-size: 10px;
  font-weight: 600;
  color: var(--color-text-tertiary);
}
.rx-analysis-source {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 1px 6px;
  border-radius: var(--radius-sm);
  background: color-mix(in srgb, var(--color-accent) 10%, transparent);
  border: 1px solid color-mix(in srgb, var(--color-accent) 25%, transparent);
  font-size: 10px;
  font-weight: 600;
  color: var(--color-accent);
  font-family: "Cascadia Code", "Fira Code", "Consolas", monospace;
}
.rx-sql-block {
  margin: var(--spacing-sm) 0 0;
  padding: var(--spacing-md);
  border-radius: var(--radius-md);
  background: var(--color-code-bg);
  border: 1px solid var(--color-code-border);
  font-family: "Cascadia Code", "Fira Code", "Consolas", monospace;
  font-size: 12px;
  line-height: 1.6;
  overflow: auto;
  white-space: pre-wrap;
  color: var(--color-text-secondary);
  max-height: 280px;
}
/* ── Response text ───────────────────────────────────────────────────── */
.rx-response-text {
  font-size: 13px;
  line-height: 1.6;
  color: var(--color-text);
  overflow-wrap: anywhere;
}
.rx-md-p {
  margin: 0 0 var(--spacing-xs);
}
.rx-md-p:last-child {
  margin-bottom: 0;
}
.rx-md-list {
  margin: var(--spacing-xs) 0;
  padding-left: 20px;
}
.rx-md-list li {
  margin-bottom: 2px;
}
.rx-md-code {
  padding: 1px 5px;
  border-radius: 4px;
  background: var(--color-code-bg);
  border: 1px solid var(--color-code-border);
  font-family: "Cascadia Code", "Fira Code", "Consolas", monospace;
  font-size: 11.5px;
}
/* ── Follow-up questions ─────────────────────────────────────────────── */
.rx-followups {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-sm);
  margin-top: var(--spacing-md);
}
.rx-followup {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: var(--spacing-sm) var(--spacing-md);
  border-radius: var(--radius-md);
  border: 1px solid var(--color-border);
  background: var(--color-surface);
  color: var(--color-accent);
  font-size: 12px;
  font-weight: 500;
  text-align: left;
  cursor: pointer;
  transition: background 120ms, border-color 120ms;
  max-width: 100%;
}
.rx-followup:hover {
  background: var(--color-accent-subtle);
  border-color: var(--color-accent);
}
/* ── Feedback ────────────────────────────────────────────────────────── */
.rx-feedback {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
  margin-top: var(--spacing-md);
  padding-top: var(--spacing-sm);
}
.rx-feedback-label {
  font-size: 11px;
  color: var(--color-text-tertiary);
}
.rx-feedback-label--done {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: var(--color-success);
  font-weight: 600;
}
.rx-feedback-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--color-text-tertiary);
  cursor: pointer;
  transition: all 120ms;
}
.rx-feedback-btn:hover:not(:disabled) {
  background: var(--color-surface-subtle);
  color: var(--color-text);
  border-color: var(--color-text-tertiary);
}
.rx-feedback-btn--active {
  background: var(--color-accent-subtle);
  color: var(--color-accent);
  border-color: var(--color-accent);
}
.rx-feedback-btn:disabled {
  opacity: 0.4;
  cursor: not-allowed;
}
.rx-feedback-form {
  display: flex;
  gap: var(--spacing-sm);
  align-items: flex-start;
  margin-top: var(--spacing-sm);
}
.rx-feedback-error {
  margin: var(--spacing-sm) 0 0;
  font-size: 12px;
  color: var(--color-error);
}
/* ── Loading dots ────────────────────────────────────────────────────── */
.rx-loading-dots {
  display: flex;
  gap: 4px;
  align-items: center;
}
.rx-loading-dots span {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--color-text-tertiary);
  animation: rx-bounce 1.2s infinite ease-in-out;
}
.rx-loading-dots span:nth-child(2) {
  animation-delay: 0.15s;
}
.rx-loading-dots span:nth-child(3) {
  animation-delay: 0.3s;
}
@keyframes rx-bounce {
  0%,
  80%,
  100% {
    transform: scale(0.6);
    opacity: 0.4;
  }
  40% {
    transform: scale(1);
    opacity: 1;
  }
}
.rx-loading-text {
  font-size: 12px;
  color: var(--color-text-tertiary);
}
/* ── Data View ───────────────────────────────────────────────────────── */
.rx-dataview {
  margin-top: var(--spacing-md);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  overflow: hidden;
  background: var(--color-surface);
}
/* ── Data View: toolbar ──────────────────────────────────────────────── */
.rx-dv-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-sm);
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-surface-subtle);
  border-bottom: 1px solid var(--color-border);
}
.rx-dv-toolbar-left,
.rx-dv-toolbar-right {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}
.rx-dv-result-badge {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  font-size: 11px;
  font-weight: 600;
  color: var(--color-text-secondary);
}
.rx-dv-action {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border: none;
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--color-text-tertiary);
  cursor: pointer;
  transition: background 100ms, color 100ms;
}
.rx-dv-action:hover {
  background: var(--color-surface-strong);
  color: var(--color-text);
}
.rx-dv-action--text {
  width: auto;
  padding: 0 var(--spacing-sm);
  gap: 4px;
  font-size: 11px;
  font-weight: 600;
}
.rx-dv-action--active {
  color: var(--color-accent);
}
.rx-dv-sep {
  width: 1px;
  height: 16px;
  background: var(--color-border);
}
.rx-dv-tab {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--color-text-tertiary);
  cursor: pointer;
  transition: all 100ms;
}
.rx-dv-tab:hover {
  background: var(--color-surface-strong);
  color: var(--color-text);
}
.rx-dv-tab--active {
  background: var(--color-surface);
  color: var(--color-accent);
  border-color: var(--color-border);
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.05);
}
/* ── Data View: code block ───────────────────────────────────────────── */
.rx-dv-code {
  border-bottom: 1px solid var(--color-border);
  background: var(--color-code-bg);
  max-height: 320px;
  overflow: auto;
}
.rx-dv-code pre {
  margin: 0;
  padding: var(--spacing-md);
  font-family: "Cascadia Code", "Fira Code", "Consolas", monospace;
  font-size: 12px;
  line-height: 1.6;
  white-space: pre-wrap;
  color: var(--color-text-secondary);
}
/* ── Data View: chart bar ────────────────────────────────────────────── */
.rx-dv-chartbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-sm);
  padding: var(--spacing-xs) var(--spacing-md);
  background: var(--color-surface-subtle);
  border-bottom: 1px solid var(--color-border);
}
.rx-dv-charttypes {
  display: flex;
  gap: 2px;
}
.rx-dv-charttype {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 3px 8px;
  border: 1px solid transparent;
  border-radius: var(--radius-sm);
  background: transparent;
  color: var(--color-text-tertiary);
  font-size: 10px;
  font-weight: 600;
  cursor: pointer;
  transition: all 100ms;
}
.rx-dv-charttype:hover {
  color: var(--color-text);
  background: var(--color-surface-strong);
}
.rx-dv-charttype--active {
  color: var(--color-accent);
  background: var(--color-surface);
  border-color: var(--color-border);
}
/* ── Data View: config panel ─────────────────────────────────────────── */
.rx-dv-config {
  display: flex;
  gap: var(--spacing-lg);
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--color-surface-subtle);
  border-bottom: 1px solid var(--color-border);
  flex-wrap: wrap;
}
.rx-dv-config-field {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.rx-dv-config-label {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--color-text-tertiary);
}
.rx-dv-select {
  padding: 3px 8px;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  background: var(--color-surface);
  color: var(--color-text);
  font-size: 11px;
  font-family: inherit;
  min-width: 100px;
}
/* ── Data View: chart container ──────────────────────────────────────── */
.rx-dv-chart {
  padding: var(--spacing-md);
  display: flex;
  justify-content: center;
}
.rx-dv-chart svg {
  color: var(--color-text);
}
/* ── Table ────────────────────────────────────────────────────────────── */
.rx-table-container {
  overflow: auto;
  max-height: 320px;
}
.rx-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 12px;
}
.rx-table th,
.rx-table td {
  padding: 6px var(--spacing-md);
  border-top: 1px solid var(--color-border-subtle);
  text-align: left;
  white-space: nowrap;
}
.rx-table th {
  position: sticky;
  top: 0;
  background: var(--color-surface);
  font-weight: 600;
  font-size: 11px;
  color: var(--color-text-secondary);
  z-index: 1;
  border-top: none;
}
.rx-th-inner {
  display: inline-flex;
  align-items: center;
  gap: 5px;
}
.rx-col-type {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 20px;
  height: 16px;
  padding: 0 3px;
  border-radius: 3px;
  font-size: 9px;
  font-weight: 700;
  font-family: "Cascadia Code", "Consolas", monospace;
  letter-spacing: 0;
}
.rx-col-type--str {
  background: color-mix(in srgb, #6366f1 12%, transparent);
  color: #6366f1;
}
.rx-col-type--num {
  background: color-mix(in srgb, #0891b2 12%, transparent);
  color: #0891b2;
}
.rx-col-type--date {
  background: color-mix(in srgb, #d97706 12%, transparent);
  color: #d97706;
}
.rx-th-rownum,
.rx-td-rownum {
  width: 32px;
  min-width: 32px;
  text-align: right;
  color: var(--color-text-tertiary);
  font-size: 11px;
  font-variant-numeric: tabular-nums;
  padding-right: var(--spacing-md);
  user-select: none;
}
.rx-td--num {
  text-align: right;
  font-variant-numeric: tabular-nums;
}
.rx-table tbody tr:hover {
  background: var(--color-surface-subtle);
}
.rx-table-overflow {
  padding: var(--spacing-sm) var(--spacing-md);
  font-size: 11px;
  color: var(--color-text-tertiary);
  text-align: center;
  border-top: 1px solid var(--color-border-subtle);
}
/* ── Compose area ────────────────────────────────────────────────────── */
.rx-compose {
  flex-shrink: 0;
  padding: var(--spacing-md) var(--spacing-lg);
  border-top: 1px solid var(--color-border);
  background: var(--color-surface);
}
.rx-status {
  font-size: 11px;
  color: var(--color-text-tertiary);
  margin-bottom: var(--spacing-sm);
}
.rx-compose-row {
  display: flex;
  gap: var(--spacing-sm);
  align-items: flex-end;
}
.rx-textarea {
  width: 100%;
  box-sizing: border-box;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  background: var(--color-base);
  color: var(--color-text);
  font: inherit;
  font-size: 13px;
  padding: var(--spacing-sm) var(--spacing-md);
  resize: none;
  line-height: 1.5;
}
.rx-textarea:focus {
  outline: none;
  border-color: var(--color-accent);
  box-shadow: 0 0 0 2px var(--color-accent-subtle);
}
.rx-textarea--compose {
  min-height: 38px;
  max-height: 120px;
  flex: 1;
}
.rx-textarea--feedback {
  min-height: 32px;
  flex: 1;
  font-size: 12px;
}
.rx-compose-actions {
  display: flex;
  gap: var(--spacing-sm);
  flex-shrink: 0;
}
/* ── Buttons ─────────────────────────────────────────────────────────── */
.rx-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border: none;
  border-radius: var(--radius-md);
  padding: 0 var(--spacing-lg);
  min-height: 38px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
  transition: background 120ms, opacity 120ms;
  white-space: nowrap;
}
.rx-btn:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}
.rx-btn--primary {
  background: var(--color-accent);
  color: #ffffff;
}
.rx-btn--primary:hover:not(:disabled) {
  background: var(--color-accent-hover);
}
.rx-btn--ghost {
  background: transparent;
  color: var(--color-text-tertiary);
  padding: 0 var(--spacing-sm);
  min-height: 28px;
  font-size: 12px;
}
.rx-btn--ghost:hover:not(:disabled) {
  color: var(--color-text);
  background: var(--color-surface-subtle);
}
.rx-btn--sm {
  min-height: 28px;
  padding: 0 var(--spacing-sm);
  font-size: 12px;
  border-radius: var(--radius-sm);
}
/* ── Focus ───────────────────────────────────────────────────────────── */
.rx-btn:focus-visible,
.rx-prompt:focus-visible,
.rx-chip:focus-visible,
.rx-textarea:focus-visible,
.rx-followup:focus-visible,
.rx-feedback-btn:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 1px;
}
/* ── Scrollbar ───────────────────────────────────────────────────────── */
.rx-chat::-webkit-scrollbar,
.rx-table-container::-webkit-scrollbar,
.rx-dv-code::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
.rx-chat::-webkit-scrollbar-thumb,
.rx-table-container::-webkit-scrollbar-thumb,
.rx-dv-code::-webkit-scrollbar-thumb {
  background: var(--color-surface-strong);
  border-radius: 999px;
}
/* ── Compact mode ────────────────────────────────────────────────────── */
.rx-shell--compact .rx-header {
  padding: var(--spacing-sm) var(--spacing-md);
}
.rx-shell--compact .rx-title {
  font-size: 13px;
}
.rx-shell--compact .rx-chat {
  padding: var(--spacing-md);
}
.rx-shell--compact .rx-compose {
  padding: var(--spacing-sm) var(--spacing-md);
}
.rx-shell--compact .rx-genie-response {
  max-width: 100%;
}
.rx-shell--compact .rx-context-strip {
  padding: var(--spacing-xs) var(--spacing-md);
}
